package com.example.myandroid

import android.content.Context
import android.os.Handler
import android.os.Looper

/**
 * This class acts as the communication layer between the dynamically loaded DEX UI 
 * and our host application. The DEX UI can invoke these methods via reflection or casting.
 */
class NativeUiBridge(val context: Context) {
    fun close() {
        Handler(Looper.getMainLooper()).post { NativeUiManager.removeOverlay(context) }
    }

    fun log(msg: String) {
